//go:build builtinassets
// +build builtinassets

package ui

import "embed"

// EmbedFS is the prometheus UI asset bundle.
//
// Upstream populates this via web/ui/embed.go, which is generated by
// scripts/compress_assets.sh after building the React/Mantine apps and
// is gitignored. Downstreams (notably promxy) build with the
// `builtinassets` tag but do not serve the prometheus UI, so the
// generated file is absent and the symbol would be undefined. This stub
// declares an empty embed.FS so the package compiles in that
// configuration; if a real embed.go is generated alongside this file
// the duplicate declaration will surface, which is the expected signal
// to drop this stub for the asset-building build.

//go:embed README.md
var EmbedFS embed.FS
